-- ============================================================
-- Koto no Ha — Perbaikan tabrakan antar-level & entri kanji rusak
-- Kebijakan: LEVEL LEBIH TINGGI MENANG.
--   - 73 kanji N3 yang juga ada di N2/N1 dihapus dari N3 (N3 kalah)
--     lalu diganti 73 kanji N3 baru (eksklusif).
--   - 3 kanji N2 (優,訟,訴) yang juga ada di N1 dihapus dari N2 (N1 menang)
--     lalu diganti 3 kanji N2 baru.
--   - 20 entri "kanji" 2-karakter (kata, bukan kanji) di N2 & N1 dihapus
--     lalu diganti kanji tunggal valid (9 N2 + 11 N1).
-- Total: hapus 73 N3 + 3 N2 + 20 rusak; tambah 73 N3 + 12 N2 + 11 N1 = 96.
-- Bacaan & arti kanji pengganti bersumber dari daftar JLPT (jlptsensei/Jisho),
-- arti/hint ditulis Bahasa Indonesia mengikuti gaya 004 & 010.
-- WAJIB dijalankan SETELAH 014_dedup_kanji.sql (butuh unique index utk ON CONFLICT).
-- Idempoten: penghapusan computed; insert pakai ON CONFLICT DO NOTHING.
-- Hasil akhir per level: N3=194, N2=250, N1=250 (semua unik global & 1 karakter).
-- ============================================================

-- ─── 1. Hapus 73 kanji N3 yang kalah (juga ada di N2/N1) ─────────────────────
DELETE FROM public.kanji n3
WHERE n3.level_id = 3
  AND EXISTS (SELECT 1 FROM public.kanji hi WHERE hi.kanji = n3.kanji AND hi.level_id > 3);

-- ─── 2. Hapus 3 kanji N2 yang kalah dari N1 ──────────────────────────────────
DELETE FROM public.kanji WHERE level_id = 4 AND kanji IN ('優','訟','訴');

-- ─── 3. Hapus 20 entri rusak (2 karakter, sebenarnya kata) di N2 & N1 ────────
DELETE FROM public.kanji WHERE level_id IN (4,5) AND char_length(kanji) > 1;

-- ─── 4. Tambah 96 kanji pengganti (order_index di-append setelah max) ────────
ON CONFLICT (level_id, kanji) DO NOTHING;

-- ─── DONE ────────────────────────────────────────────────────────────────────
-- Verifikasi:
--   SELECT level_id, count(*) FROM public.kanji GROUP BY 1 ORDER BY 1;  -- 3=194,4=250,5=250
--   SELECT kanji FROM public.kanji GROUP BY kanji HAVING count(DISTINCT level_id)>1;  -- 0 baris
--   SELECT kanji FROM public.kanji WHERE char_length(kanji)<>1;  -- 0 baris
